// ETAPA 2 - Logica de dominio IoT
// Responsabilidad: analizar lectura contra umbrales y determinar nivel de alerta
// Sin conocimiento de BD ni canales de notificacion

const { run_id, start_ts, lectura } = $input.item.json;
const e2_start = new Date().toISOString();

// Umbrales centralizados segun ADR-002 (ASHRAE 62.1 / ISO 7730)
// CR1: cambiar un umbral = modificar solo esta constante
const UMBRALES = {
  temperature: { min: 10, max: 35, critical_max: 45 },
  humidity:    { min: 20, max: 80, critical_max: 95 },
  co2:         { max: 800, critical_max: 1200 }  // ASHRAE 62.1: 800 ppm alerta, 1200 ppm critico
};

// Enum oficial ADR-002: normal | advertencia | critico (todo en español)
const anomalias = [];
let nivel = 'normal';

// Analisis temperatura
if (lectura.temperature > UMBRALES.temperature.critical_max) {
  anomalias.push({ campo: 'temperature', valor: lectura.temperature, umbral: UMBRALES.temperature.critical_max, tipo: 'critico' });
  nivel = 'critico';
} else if (lectura.temperature > UMBRALES.temperature.max || lectura.temperature < UMBRALES.temperature.min) {
  const umbral = lectura.temperature > UMBRALES.temperature.max ? UMBRALES.temperature.max : UMBRALES.temperature.min;
  anomalias.push({ campo: 'temperature', valor: lectura.temperature, umbral, tipo: 'advertencia' });
  if (nivel !== 'critico') nivel = 'advertencia';
}

// Analisis humedad
if (lectura.humidity > UMBRALES.humidity.critical_max) {
  anomalias.push({ campo: 'humidity', valor: lectura.humidity, umbral: UMBRALES.humidity.critical_max, tipo: 'critico' });
  nivel = 'critico';
} else if (lectura.humidity > UMBRALES.humidity.max) {
  anomalias.push({ campo: 'humidity', valor: lectura.humidity, umbral: UMBRALES.humidity.max, tipo: 'advertencia' });
  if (nivel !== 'critico') nivel = 'advertencia';
}

// Analisis CO2
if (lectura.co2 > UMBRALES.co2.critical_max) {
  anomalias.push({ campo: 'co2', valor: lectura.co2, umbral: UMBRALES.co2.critical_max, tipo: 'critico' });
  nivel = 'critico';
} else if (lectura.co2 > UMBRALES.co2.max) {
  anomalias.push({ campo: 'co2', valor: lectura.co2, umbral: UMBRALES.co2.max, tipo: 'advertencia' });
  if (nivel !== 'critico') nivel = 'advertencia';
}

const requiereNotificacion = nivel !== 'normal';
// R001=normal, R002=advertencia, R003=critico (REC-002: trazabilidad de regla aplicada)
const regla_aplicada = nivel === 'normal' ? 'R001' : nivel === 'advertencia' ? 'R002' : 'R003';

const e2_end = new Date().toISOString();
const duracion_ms = new Date(e2_end) - new Date(e2_start);

console.log(JSON.stringify({
  run_id, etapa: 'E2_dominio_iot',
  status: 'ok', nivel, regla_aplicada,
  sensor_id: lectura.sensor_id,
  anomalias_detectadas: anomalias.length,
  e2_start, e2_end, duracion_ms
}));

// umbrales_usados omitido del output — es dominio interno de E2 (ISP)
const analisis = { nivel, anomalias, requiereNotificacion, regla_aplicada };

return [{ json: { run_id, start_ts, e2_start, e2_end, lectura, analisis } }];
